diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index 4d3de76389c2..5bcaff253cde 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -3065,6 +3065,7 @@ static Instruction *foldNestedSelects(SelectInst &OuterSelVal,
                             !IsAndVariant ? SelInner : InnerSel.FalseVal);
 }

+
 Instruction *InstCombinerImpl::foldSelectOfBools(SelectInst &SI) {
   Value *CondVal = SI.getCondition();
   Value *TrueVal = SI.getTrueValue();
@@ -3320,9 +3321,49 @@ Instruction *InstCombinerImpl::foldSelectOfBools(SelectInst &SI) {
     }
   }

+  // Transform select (select Cond, Cmp1, false), Cmp2, false
+  // into select Cond, (icmp ult X, C), false when Cmp1 and Cmp2 are signed
+  // comparisons that can be combined into an unsigned range check.
+  // Pattern: select (select Cond, Cmp1, false), Cmp2, false
+  if (match(FalseVal, m_Zero())) {
+    Value *InnerCond;
+    Value *LHS1, *RHS1, *LHS2, *RHS2;
+    ICmpInst::Predicate Pred1, Pred2;
+    if (match(CondVal, m_Select(m_Value(InnerCond),
+                                m_ICmp(Pred1, m_Value(LHS1), m_Value(RHS1)),
+                                m_Zero())) &&
+        match(TrueVal, m_ICmp(Pred2, m_Value(LHS2), m_Value(RHS2)))) {
+      // Both comparisons must share the same first operand.
+      if (LHS1 != LHS2)
+        return nullptr;
+
+      // Cmp1 must be a signed greater-than-or-equal to 0.
+      // This can be: icmp sge X, 0  or  icmp sgt X, -1
+      bool IsNonNegativeCheck = false;
+      if (Pred1 == ICmpInst::ICMP_SGE && match(RHS1, m_Zero()))
+        IsNonNegativeCheck = true;
+      else if (Pred1 == ICmpInst::ICMP_SGT && match(RHS1, m_AllOnes()))
+        IsNonNegativeCheck = true;
+
+      if (!IsNonNegativeCheck)
+        return nullptr;
+
+      // Cmp2 must be a signed less-than with a positive constant.
+      ConstantInt *C2;
+      if (Pred2 != ICmpInst::ICMP_SLT ||
+          !match(RHS2, m_ConstantInt(C2)) || C2->isNegative())
+        return nullptr;
+
+      // Combine into unsigned less-than.
+      Value *NewCmp = Builder.CreateICmpULT(LHS1, C2);
+      return SelectInst::Create(InnerCond, NewCmp, Zero);
+    }
+  }
+
   return nullptr;
 }

+
 // Return true if we can safely remove the select instruction for std::bit_ceil
 // pattern.
 static bool isSafeToRemoveBitCeilSelect(ICmpInst::Predicate Pred, Value *Cond0,

